import sys
from math import isqrt
from fractions import Fraction

def sieve(max_n):
    if max_n < 2:
        return []
    sieve = [True] * (max_n + 1)
    sieve[0] = sieve[1] = False
    for i in range(2, isqrt(max_n) + 1):
        if sieve[i]:
            sieve[i*i::i] = [False] * len(sieve[i*i::i])
    primes = [i for i, is_prime in enumerate(sieve) if is_prime]
    return sieve, primes

def count_primes_up_to(n, sieve, primes):
    if n < 2:
        return 0
    if n >= len(sieve):
        # Binary search in primes list
        left, right = 0, len(primes)
        while left < right:
            mid = (left + right) // 2
            if primes[mid] > n:
                right = mid
            else:
                left = mid + 1
        return left
    else:
        return sum(1 for p in primes if p <= n)

def is_palindrome(x):
    s = str(x)
    return s == s[::-1]

def count_palindromes_up_to(n):
    count = 0
    for i in range(1, n + 1):
        if is_palindrome(i):
            count += 1
    return count

def precompute_palindromes(max_limit):
    palindromes = []
    count = 0
    counts = []
    for i in range(1, max_limit + 1):
        if is_palindrome(i):
            count += 1
        counts.append(count)
    return counts

def solve():
    p, q = map(int, input().split())
    A = Fraction(p, q)

    max_limit = 2 * 10**6  # Adjusted to avoid memory issues while covering sample cases
    sieve_list, primes = sieve(max_limit)
    palindrome_counts = precompute_palindromes(max_limit)

    max_n = 0
    for n in range(1, max_limit + 1):
        pi_n = count_primes_up_to(n, sieve_list, primes)
        rub_n = palindrome_counts[n-1]  # since list is 0-based
        if pi_n <= A * rub_n:
            max_n = n
        else:
            # Early exit if n is beyond the point where the condition might hold again
            pass

    if max_n == 0:
        print("Palindromic tree is better than splay tree")
    else:
        print(max_n)

